"""FastAPI application for the Order Service."""

from fastapi import FastAPI, HTTPException, status
from fastapi.responses import JSONResponse
from contextlib import asynccontextmanager

from .models import (
    OrderCreate,
    OrderResponse,
    ErrorResponse,
)
from .services import (
    create_order,
    get_order,
    pay_order,
    cancel_order,
    OrderNotFoundError,
    InvalidOrderStateError,
    ServiceUnavailableError,
)
from .inventory_client import (
    ProductNotFoundError,
    InsufficientStockError,
    InventoryServiceError,
    ServiceConnectionError,
)
from .database import init_orders_db


@asynccontextmanager
async def lifespan(app: FastAPI):
    """Initialize database on startup."""
    init_orders_db()
    yield


app = FastAPI(
    title="Order Service",
    description="Manages order CRUD, state machine, and coordinates with Inventory Service",
    version="1.0.0",
    lifespan=lifespan,
)


@app.exception_handler(OrderNotFoundError)
async def order_not_found_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_404_NOT_FOUND,
        content={"error": "Order not found", "detail": str(exc)},
    )


@app.exception_handler(InsufficientStockError)
async def insufficient_stock_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_400_BAD_REQUEST,
        content={"error": "Insufficient stock", "detail": str(exc)},
    )


@app.exception_handler(ProductNotFoundError)
async def product_not_found_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_404_NOT_FOUND,
        content={"error": "Product not found", "detail": str(exc)},
    )


@app.exception_handler(InvalidOrderStateError)
async def invalid_order_state_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_400_BAD_REQUEST,
        content={"error": "Invalid order state", "detail": str(exc)},
    )


@app.exception_handler(ServiceUnavailableError)
async def service_unavailable_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
        content={"error": "Service unavailable", "detail": str(exc)},
    )


@app.exception_handler(ServiceConnectionError)
async def service_connection_error_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
        content={"error": "Service unavailable", "detail": str(exc)},
    )


@app.exception_handler(InventoryServiceError)
async def inventory_service_error_handler(request, exc):
    return JSONResponse(
        status_code=status.HTTP_503_SERVICE_UNAVAILABLE,
        content={"error": "Inventory Service error", "detail": str(exc)},
    )


@app.post("/orders", response_model=OrderResponse, status_code=status.HTTP_201_CREATED)
async def create_new_order(order_data: OrderCreate):
    """
    Create a new order with inventory reservation.

    - **user_id**: The user ID placing the order
    - **items**: List of items with product_id and quantity

    This endpoint calls the Inventory Service to reserve stock.
    """
    items = [{"product_id": item.product_id, "quantity": item.quantity} for item in order_data.items]
    order = create_order(order_data.user_id, items)

    return OrderResponse(
        id=order["id"],
        user_id=order["user_id"],
        status=order["status"],
        items=[
            {
                "product_id": item["product_id"],
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
            }
            for item in order["items"]
        ],
        total_amount=order["total_amount"],
        created_at=order["created_at"],
    )


@app.get("/orders/{order_id}", response_model=OrderResponse)
async def get_order_details(order_id: str):
    """
    Get order details by ID.

    - **order_id**: The order ID to retrieve
    """
    order = get_order(order_id)
    if not order:
        raise HTTPException(
            status_code=status.HTTP_404_NOT_FOUND,
            detail=f"Order {order_id} not found",
        )

    return OrderResponse(
        id=order["id"],
        user_id=order["user_id"],
        status=order["status"],
        items=[
            {
                "product_id": item["product_id"],
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
            }
            for item in order["items"]
        ],
        total_amount=order["total_amount"],
        created_at=order["created_at"],
    )


@app.post("/orders/{order_id}/pay", response_model=OrderResponse)
async def pay_order_endpoint(order_id: str):
    """
    Pay for an order.

    This endpoint calls the Inventory Service to confirm stock deduction.

    - **order_id**: The order ID to pay
    """
    order = pay_order(order_id)

    return OrderResponse(
        id=order["id"],
        user_id=order["user_id"],
        status=order["status"],
        items=[
            {
                "product_id": item["product_id"],
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
            }
            for item in order["items"]
        ],
        total_amount=order["total_amount"],
        created_at=order["created_at"],
    )


@app.post("/orders/{order_id}/cancel", response_model=OrderResponse)
async def cancel_order_endpoint(order_id: str):
    """
    Cancel an order.

    This endpoint calls the Inventory Service to release reserved stock.

    - **order_id**: The order ID to cancel
    """
    order = cancel_order(order_id)

    return OrderResponse(
        id=order["id"],
        user_id=order["user_id"],
        status=order["status"],
        items=[
            {
                "product_id": item["product_id"],
                "quantity": item["quantity"],
                "unit_price": item["unit_price"],
            }
            for item in order["items"]
        ],
        total_amount=order["total_amount"],
        created_at=order["created_at"],
    )


if __name__ == "__main__":
    import uvicorn
    uvicorn.run(app, host="0.0.0.0", port=8081)

"""HTTP client for calling Inventory Service."""

import httpx
from typing import Optional

INVENTORY_SERVICE_URL = "http://localhost:8082"


class InventoryServiceError(Exception):
    """Raised when Inventory Service returns an error."""
    pass


class ProductNotFoundError(Exception):
    """Raised when product is not found in Inventory Service."""
    pass


class InsufficientStockError(Exception):
    """Raised when there is insufficient stock."""
    pass


class ServiceConnectionError(Exception):
    """Raised when unable to connect to Inventory Service."""
    pass


def handle_inventory_response(response: httpx.Response) -> dict:
    """Handle response from Inventory Service and raise appropriate errors."""
    if response.status_code == 404:
        raise ProductNotFoundError(f"Product not found: {response.json().get('detail', 'Unknown')}")
    elif response.status_code == 400:
        error_data = response.json()
        raise InsufficientStockError(error_data.get("detail", str(error_data)))
    elif response.status_code >= 400:
        error_data = response.json()
        raise InventoryServiceError(f"Inventory Service error: {error_data.get('error', 'Unknown')}")
    return response.json()


def reserve_stock(product_id: str, quantity: int) -> dict:
    """
    Call Inventory Service to reserve stock.

    Args:
        product_id: The product ID
        quantity: The quantity to reserve

    Returns:
        Stock info dict with available_stock and reserved_stock

    Raises:
        ProductNotFoundError: If the product does not exist
        InsufficientStockError: If there is not enough available stock
        ServiceConnectionError: If the service is unavailable
    """
    try:
        with httpx.Client(timeout=10.0) as client:
            response = client.post(
                f"{INVENTORY_SERVICE_URL}/products/{product_id}/reserve",
                json={"quantity": quantity}
            )
            return handle_inventory_response(response)
    except Exception as e:
        if "connect" in str(e).lower() or "timeout" in str(e).lower():
            raise ServiceConnectionError(f"Failed to connect to Inventory Service: {e}")
        raise


def release_stock(product_id: str, quantity: int) -> dict:
    """
    Call Inventory Service to release reserved stock.

    Args:
        product_id: The product ID
        quantity: The quantity to release

    Returns:
        Stock info dict

    Raises:
        ProductNotFoundError: If the product does not exist
        ServiceConnectionError: If the service is unavailable
    """
    try:
        with httpx.Client(timeout=10.0) as client:
            response = client.post(
                f"{INVENTORY_SERVICE_URL}/products/{product_id}/release",
                json={"quantity": quantity}
            )
            return handle_inventory_response(response)
    except Exception as e:
        if "connect" in str(e).lower() or "timeout" in str(e).lower():
            raise ServiceConnectionError(f"Failed to connect to Inventory Service: {e}")
        raise


def confirm_stock(product_id: str, quantity: int) -> dict:
    """
    Call Inventory Service to confirm stock deduction.

    Args:
        product_id: The product ID
        quantity: The quantity to confirm/deduct

    Returns:
        Stock info dict

    Raises:
        ProductNotFoundError: If the product does not exist
        ServiceConnectionError: If the service is unavailable
    """
    try:
        with httpx.Client(timeout=10.0) as client:
            response = client.post(
                f"{INVENTORY_SERVICE_URL}/products/{product_id}/confirm",
                json={"quantity": quantity}
            )
            return handle_inventory_response(response)
    except Exception as e:
        if "connect" in str(e).lower() or "timeout" in str(e).lower():
            raise ServiceConnectionError(f"Failed to connect to Inventory Service: {e}")
        raise


def get_product_stock(product_id: str) -> dict:
    """
    Call Inventory Service to get product stock info.

    Args:
        product_id: The product ID

    Returns:
        Stock info dict

    Raises:
        ProductNotFoundError: If the product does not exist
        ServiceConnectionError: If the service is unavailable
    """
    try:
        with httpx.Client(timeout=10.0) as client:
            response = client.get(f"{INVENTORY_SERVICE_URL}/products/{product_id}/stock")
            return handle_inventory_response(response)
    except Exception as e:
        if "connect" in str(e).lower() or "timeout" in str(e).lower():
            raise ServiceConnectionError(f"Failed to connect to Inventory Service: {e}")
        raise

"""Data models for the Inventory Service."""

from pydantic import BaseModel
from typing import Optional


class StockAdjustRequest(BaseModel):
    stock: int


class StockResponse(BaseModel):
    product_id: str
    available_stock: int
    reserved_stock: int


class ReserveRequest(BaseModel):
    quantity: int


class ConfirmRequest(BaseModel):
    quantity: int


class ReleaseRequest(BaseModel):
    quantity: int


class ErrorResponse(BaseModel):
    error: str
    detail: Optional[str] = None


class ProductCreate(BaseModel):
    product_id: str
    name: str = "Product"
    price: float = 0.0
    stock: int = 0
